import React from "react";
import { Title } from "../About/aboutElements";
import {
  Arrow,
  ArrowBox,
  ArrowBoxMobile,
  ArrowMobile,
  Date,
  Datebar,
  Description,
  Descriptionbar,
  OpenText,
  Textbar,
  Tile,
  TileColumn,
  Titlebar,
  Video,
  Videobar,
  Worksbar,
  WorksComponent,
  WorksContent,
  WorkTitle,
  WorkTitlebar,
} from "./worksElements";

import Typewriter from "typewriter-effect";

import gitfinder from "../../videos/gitfinder.mp4";

const Works = () => {
  return (
    <>
      <WorksComponent>
        <Worksbar>
          <Titlebar>
            <Title>Works</Title>
          </Titlebar>
          <WorksContent>
            <Textbar>
              <OpenText>
                <Typewriter
                  options={{
                    strings: ["Some of mine."],
                    autoStart: true,
                    loop: true,
                    pauseFor: "2500",
                    cursorClassName: "cursorType",
                  }}
                />
              </OpenText>
            </Textbar>
            <Tiles />
          </WorksContent>
        </Worksbar>
      </WorksComponent>
    </>
  );
};

const Tiles = () => {
  return (
    <TileColumn style={{ marginTop: "100px" }}>
      <Tile>
        <Videobar>
          <Video
            src={gitfinder}
            muted
            autoPlay={true}
            loop="true"
            playsinline
          />
        </Videobar>
        <WorkTitlebar>
          <WorkTitle>Gitfinder</WorkTitle>
          <ArrowBox>
            <Arrow />
          </ArrowBox>
        </WorkTitlebar>
        <Descriptionbar>
          <Description>Tool for finding and showing information about GitHub users. It is based on the API. It allows you to use two brightness modes. Application shows the most important information about the searched GitHub user. Find yourself there, developer!</Description>
        </Descriptionbar>
        <Datebar>
          <Date>June, 2021</Date>
          <ArrowBoxMobile><ArrowMobile/></ArrowBoxMobile>
        </Datebar>
      </Tile>
    </TileColumn>
  );
};

export default Works;
